2783	/// rbcc_Constants.sh RBCC_fact_ext_audit_hallmark.
2784	const RBTDRC_FACT_EXT_AUDIT_HALLMARK: &str = "audit-hallmark";
2785	
2786	/// Multi-fact extension emitted by `rbw-lE` (rbld_ensconce): one
2787	/// `<touchmark>.lode` capture-file per ensconced Lode, carrying the provenance
2788	/// envelope. Its root is the Lode touchmark. Mirrors rbcc_Constants.sh
2789	/// RBCC_fact_ext_lode.
2790	const RBTDRC_FACT_EXT_LODE: &str = "lode";
2791	
2792	/// Bole-Lode member tags asserted by divine inspect. Mirror rbgc_Constants.sh
2793	/// RBGC_LODE_TAG_BOLE / RBGC_LODE_TAG_VOUCH / RBGC_LODE_TAG_DIGEST_PREFIX.
2794	const RBTDRC_LODE_TAG_BOLE: &str = "rbi_bole";
2795	const RBTDRC_LODE_TAG_VOUCH: &str = "rbi_vouch";
2796	const RBTDRC_LODE_TAG_DIGEST_PREFIX: &str = "rbi_sha256-";
2797	
2798	/// BURE_TWEAK signal recognized by rbld_ensconce (rbldb_Bole.sh) to pin the Lode
2799	/// stamp, driving two captures onto one touchmark so the cloud-side collision
2800	/// guard's idempotent/collision branches fire. Mirror: rbldb_Bole.sh
2801	/// `z_ensconce_stamp_tweak_name` — same literal. Carries the buo tweak sprue,
2802	/// enforced by BURE.
2803	const RBTDRC_ENSCONCE_STAMP_TWEAK_NAME: &str = "buorb_ensconce_stamp";
2804	
2805	/// Debian-base vessel — a DIFFERENT upstream base than busybox, so ensconcing it
2806	/// onto a busybox touchmark trips the collision guard's different-digest branch.
2807	/// Carries the same yoked reliquary as busybox, so host-side skopeo resolution
2808	/// succeeds and the failure lands cloud-side at the guard, not host-side.
2809	const RBTDRC_DEB_VESSEL_DIR: &str = concat!(crate::rbtd_vessels_dir!(), "/rbev-sentry-deb-tether");
2810	
2811	fn rbtdrc_hallmark_lifecycle(dir: &Path) -> rbtdre_Verdict {
2812	    rbtdrc_with_ctx(|ctx| {
2813	        let vessel_dir = RBTDRC_BUSYBOX_VESSEL_DIR;
2814	        if !ctx.project_root().join(vessel_dir).is_dir() {
2815	            return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vessel_dir));
2816	        }
2817	
2818	        // Step 1: baseline audit.
2819	        let _ = std::fs::write(dir.join("01-audit-baseline.txt"), "auditing baseline");
2820	        let baseline_audit = match rbtdri_invoke_global(ctx, RBTDGC_AUDIT_HALLMARKS, &[], &[]) {
2821	            Ok(r) if r.exit_code == 0 => r,
2822	            Ok(r) => return rbtdre_Verdict::Fail(format!("baseline audit failed (exit {})\n{}", r.exit_code, r.stderr)),
2823	            Err(e) => return rbtdre_Verdict::Fail(format!("baseline audit invocation: {}", e)),
2824	        };
2825	        let _ = std::fs::write(dir.join("01-audit-baseline-stdout.txt"), &baseline_audit.stdout);
2826	        let baseline = match rbtdri_read_burv_facts_multi(&baseline_audit, RBTDRC_FACT_EXT_AUDIT_HALLMARK) {
2827	            Ok(v) => v,
2828	            Err(e) => return rbtdre_Verdict::Fail(format!("read baseline audit facts: {}", e)),
2829	        };
2830	        let _ = std::fs::write(dir.join("01-baseline-parsed.txt"), baseline.join("\n"));
2831	
2832	        // Step 2: ordain.
2833	        let _ = std::fs::write(dir.join("02-ordain.txt"), "ordaining busybox");
2834	        let ordain_result = match rbtdri_invoke_global(ctx, RBTDGC_ORDAIN_HALLMARK, &[vessel_dir], &[]) {
2835	            Ok(r) if r.exit_code == 0 => r,
2836	            Ok(r) => return rbtdre_Verdict::Fail(format!("ordain failed (exit {})\n{}", r.exit_code, r.stderr)),
2837	            Err(e) => return rbtdre_Verdict::Fail(format!("ordain invocation: {}", e)),
2838	        };
2839	        let hallmark = match rbtdri_read_burv_fact(&ordain_result, RBTDRC_FACT_HALLMARK) {
2840	            Ok(v) => v,
2841	            Err(e) => return rbtdre_Verdict::Fail(format!("read hallmark: {}", e)),
2842	        };
2843	        let _ = std::fs::write(dir.join("02-hallmark.txt"), &hallmark);
2844	
2845	        // Step 3: audit shows new hallmark added.
2846	        let _ = std::fs::write(dir.join("03-audit-after-ordain.txt"), "auditing after ordain");
2847	        let after_ordain_audit = match rbtdri_invoke_global(ctx, RBTDGC_AUDIT_HALLMARKS, &[], &[]) {
2848	            Ok(r) if r.exit_code == 0 => r,
2849	            Ok(r) => return rbtdre_Verdict::Fail(format!("post-ordain audit failed (exit {})\n{}", r.exit_code, r.stderr)),
2850	            Err(e) => return rbtdre_Verdict::Fail(format!("post-ordain audit invocation: {}", e)),
2851	        };
2852	        let _ = std::fs::write(dir.join("03-audit-after-ordain-stdout.txt"), &after_ordain_audit.stdout);
2853	        let after_ordain = match rbtdri_read_burv_facts_multi(&after_ordain_audit, RBTDRC_FACT_EXT_AUDIT_HALLMARK) {
2854	            Ok(v) => v,
2855	            Err(e) => return rbtdre_Verdict::Fail(format!("read post-ordain audit facts: {}", e)),
2856	        };
2857	        let mut expected_after_ordain = baseline.clone();
2858	        expected_after_ordain.push(hallmark.clone());
2859	        expected_after_ordain.sort();
2860	        if after_ordain != expected_after_ordain {
2861	            return rbtdre_Verdict::Fail(format!(
2862	                "post-ordain audit mismatch:\n  expected (baseline + new): {:?}\n  got: {:?}",
2863	                expected_after_ordain, after_ordain
2864	            ));
2865	        }
2866	
2867	        // Step 4: rekon shows all five ark basenames present.
2868	        let _ = std::fs::write(dir.join("04-rekon-after-ordain.txt"), "rekoning after ordain");
2869	        let rekon_after_ordain = match rbtdri_invoke_global(ctx, RBTDGC_REKON_HALLMARK, &[&hallmark], &[]) {
2870	            Ok(r) if r.exit_code == 0 => r,
2871	            Ok(r) => return rbtdre_Verdict::Fail(format!("post-ordain rekon failed (exit {})\n{}", r.exit_code, r.stderr)),
2872	            Err(e) => return rbtdre_Verdict::Fail(format!("post-ordain rekon invocation: {}", e)),
2873	        };
